#include<bits/stdc++.h>
using namespace std;
const int MAXN=3*1e4+5;
int main(){
    int w,n,a[MAXN],ans=0;
cin>>w>>n;
for(int i=1;i<=n;i++) cin>>a[i];
    sort(a+1,a+1+n);
for(int i=1,j=n;i<=j;j--){
	if(a[i]+a[j]<=w){
    		ans++;
      		i++;
    	}else{
      		ans++;
        }
}
    cout<<ans;
    return 0;
}
